import{_ as o,o as t,c as a,ag as i}from"./chunks/framework.DEs8X8sU.js";const u=JSON.parse('{"title":"セキュリティ監査（敵対的テストカタログ）","description":"","frontmatter":{"feature_id":"security-audit","title":"セキュリティ監査（敵対的テストカタログ）","chapter":98,"plan":["base"],"role":["posla_admin"],"audience":"internal","keywords":["security","audit","pentest","adversarial","CSRF","XSS","rate-limit","tenant-boundary"],"last_updated":"2026-04-21T00:00:00.000Z","maintainer":"posla"},"headers":[],"relativePath":"internal/98-security-audit.md","filePath":"internal/98-security-audit.md"}'),r={name:"internal/98-security-audit.md"};function s(l,e,d,n,c,p){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_98-セキュリティ監査-敵対的テストカタログ" tabindex="-1">98. セキュリティ監査（敵対的テストカタログ） <a class="header-anchor" href="#_98-セキュリティ監査-敵対的テストカタログ" aria-label="Permalink to &quot;98. セキュリティ監査（敵対的テストカタログ）&quot;">​</a></h1><p>本章は、デモ環境仮完成時点（2026-04-21）の POSLA を<strong>悪意ある攻撃者視点</strong>で精査した結果の記録。本番複製前に Critical 項目の解消を推奨する。</p><p><strong>本章の重要原則</strong>:</p><ul><li>本章の Critical / High は<strong>実コード + production HTTP で裏取り済み</strong>。</li><li>Medium / Low は agent 指摘を筆者が再評価（確度が担保できないものは §98.8 に分離）。</li><li><code>scripts/audit/</code> 配下に実行可能な検証スクリプトを添付。自動回帰に使える。</li></ul><hr><h2 id="_98-0-攻撃者モデル" tabindex="-1">98.0 攻撃者モデル <a class="header-anchor" href="#_98-0-攻撃者モデル" aria-label="Permalink to &quot;98.0 攻撃者モデル&quot;">​</a></h2><table tabindex="0"><thead><tr><th>モデル</th><th>説明</th></tr></thead><tbody><tr><td><strong>a</strong>: 外部匿名</td><td>未ログイン、URL と QR しか知らない</td></tr><tr><td><strong>b</strong>: 悪意あるスタッフ / manager</td><td>正規ログイン、限定ロール</td></tr><tr><td><strong>c</strong>: 悪意ある他テナント owner</td><td>別 tenant_id の正規 owner、URL パラメータを差し替えられる</td></tr><tr><td><strong>d</strong>: 乗っ取られた device ロール端末</td><td>正規ログイン、visible_tools 制限、物理的に店舗にある</td></tr></tbody></table><h2 id="_98-1-重要度定義" tabindex="-1">98.1 重要度定義 <a class="header-anchor" href="#_98-1-重要度定義" aria-label="Permalink to &quot;98.1 重要度定義&quot;">​</a></h2><ul><li><strong>Critical</strong>: 本番運用前に必ず修正。金銭直接損失 / 個人情報漏洩 / テナント境界破壊 / 認証情報流出</li><li><strong>High</strong>: 本番運用前に修正推奨。実運用で遭遇する / 手作業リカバリ不可</li><li><strong>Medium</strong>: 運用開始後 30 日以内に改善</li><li><strong>Low</strong>: nice-to-have / hardening / 監視強化</li></ul><h2 id="_98-2-検出件数サマリ" tabindex="-1">98.2 検出件数サマリ <a class="header-anchor" href="#_98-2-検出件数サマリ" aria-label="Permalink to &quot;98.2 検出件数サマリ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>重要度</th><th>件数</th><th>本章での採番</th></tr></thead><tbody><tr><td>Critical</td><td><strong>3</strong></td><td>C-01〜C-03</td></tr><tr><td>High</td><td><strong>14</strong></td><td>H-01〜H-14</td></tr><tr><td>Medium</td><td><strong>18</strong></td><td>M-01〜M-18</td></tr><tr><td>Low（記録のみ）</td><td>10</td><td>L-01〜L-10</td></tr><tr><td>既防御 / 誤検知（reject）</td><td>12</td><td>§98.9 参照</td></tr></tbody></table><hr><h2 id="_98-3-critical-—-本番複製前に必ず修正" tabindex="-1">98.3 Critical — 本番複製前に必ず修正 <a class="header-anchor" href="#_98-3-critical-—-本番複製前に必ず修正" aria-label="Permalink to &quot;98.3 Critical — 本番複製前に必ず修正&quot;">​</a></h2><h3 id="c-01-scripts-output-が非認証で-public-アクセス可能-🚨" tabindex="-1">C-01 <code>scripts/output/</code> が非認証で public アクセス可能 🚨 <a class="header-anchor" href="#c-01-scripts-output-が非認証で-public-アクセス可能-🚨" aria-label="Permalink to &quot;C-01 `scripts/output/` が非認証で public アクセス可能 🚨&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: <code>https://eat.posla.jp/scripts/output/helpdesk-prompt-internal.txt</code> / <code>error-codes.json</code> / その他</li><li><strong>実測</strong>: <code>curl -I https://eat.posla.jp/scripts/output/helpdesk-prompt-internal.txt</code> → <strong>HTTP 200</strong></li><li><strong>漏洩内容</strong>: <ul><li><code>helpdesk-prompt-internal.txt</code> (1.4MB): 内部マニュアル全編、運用手順、トラブルシュート、決済フロー、DB 構造、認証仕様、エラーコードマップの全文</li><li><code>error-codes.json</code>: API エラーコード完全マップ（endpoint × HTTP status × error code）</li></ul></li><li><strong>想定被害</strong>: <ul><li>内部仕様の完全リバースエンジニアリング</li><li>API 攻撃の高精度化（error code から存在有無を識別しやすい）</li><li>競合他社・攻撃者による戦略分析の無償提供</li></ul></li><li><strong>再現コマンド</strong>: <code>scripts/audit/05-static-scan.sh</code> で確認</li><li><strong>修正</strong>: <code>scripts/.htaccess</code> 新設:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Require all denied</span></span></code></pre></div>あるいは <code>public/.htaccess</code> の <code>RewriteRule</code> で <code>/scripts/</code> を 404 化</li><li><strong>確信度</strong>: 高（実測確認済）</li></ul><h3 id="c-02-public-docs-internal-が-basic-認証なしで公開されている-🚨" tabindex="-1">C-02 <code>public/docs-internal/</code> が Basic 認証なしで公開されている 🚨 <a class="header-anchor" href="#c-02-public-docs-internal-が-basic-認証なしで公開されている-🚨" aria-label="Permalink to &quot;C-02 `public/docs-internal/` が Basic 認証なしで公開されている 🚨&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: <code>https://eat.posla.jp/public/docs-internal/internal/*.html</code></li><li><strong>実測</strong>: <code>curl -I https://eat.posla.jp/public/docs-internal/internal/09-pwa.html</code> → <strong>HTTP 200</strong>、<code>WWW-Authenticate</code> ヘッダなし</li><li><strong>前提との乖離</strong>: MEMORY.md に「docs-internal (Basic認証で保護)」と明記。実態と不一致</li><li><strong>漏洩内容</strong>: POSLA 社内運営マニュアル 38 章（POSLA admin 手順 / 決済経路 / Stripe Connect / emergency / partial_multi stop 判断 / §9.36〜§9.40 全部）</li><li><strong>想定被害</strong>: 内部運営フロー全公開、POSLA 運営側の対応手順が攻撃シナリオに組み込める</li><li><strong>再現コマンド</strong>: 同上</li><li><strong>修正</strong>: <code>public/docs-internal/.htaccess</code> 新設:<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AuthType Basic</span></span>\n<span class="line"><span>AuthName &quot;POSLA Internal&quot;</span></span>\n<span class="line"><span>AuthUserFile /home/odah/.htpasswd-internal</span></span>\n<span class="line"><span>Require valid-user</span></span></code></pre></div>または Sakura コントロールパネルのディレクトリアクセス制限</li><li><strong>確信度</strong>: 高（実測確認済）</li></ul><h3 id="c-03-scripts-配下の-php-ビルドスクリプトが-public-経由で到達可能-🚨" tabindex="-1">C-03 <code>scripts/</code> 配下の PHP ビルドスクリプトが public 経由で到達可能 🚨 <a class="header-anchor" href="#c-03-scripts-配下の-php-ビルドスクリプトが-public-経由で到達可能-🚨" aria-label="Permalink to &quot;C-03 `scripts/` 配下の PHP ビルドスクリプトが public 経由で到達可能 🚨&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: <code>https://eat.posla.jp/scripts/build-helpdesk-prompt.php</code></li><li><strong>実測</strong>: <code>curl -I ...</code> → <strong>HTTP 200</strong></li><li><strong>想定被害</strong>: ビルドスクリプトのソースコード読取り / 実行経路があれば internal knowledge base 再生成トリガー / DoS</li><li><strong>補足</strong>: <code>scripts/*.py</code> 系（generate_error_catalog / enrich_error_catalog / generate-sales-pitch-pptx）も同様のリスク</li><li><strong>修正</strong>: C-01 と同じ <code>.htaccess</code> で <code>/scripts/</code> 全体 deny</li><li><strong>確信度</strong>: 高（実測確認済）</li></ul><hr><h2 id="_98-4-high-—-本番複製前に修正推奨" tabindex="-1">98.4 High — 本番複製前に修正推奨 <a class="header-anchor" href="#_98-4-high-—-本番複製前に修正推奨" aria-label="Permalink to &quot;98.4 High — 本番複製前に修正推奨&quot;">​</a></h2><h3 id="h-01-api-htaccess-に-db-credentials-が平文で記載-repo-に含まれる-⚠-phase-1-3-4-resolved-2026-04-22-phase-2-deferred" tabindex="-1">H-01 <code>api/.htaccess</code> に DB credentials が平文で記載（repo に含まれる）⚠ <strong>Phase 1+3+4 resolved 2026-04-22 / Phase 2 deferred</strong> <a class="header-anchor" href="#h-01-api-htaccess-に-db-credentials-が平文で記載-repo-に含まれる-⚠-phase-1-3-4-resolved-2026-04-22-phase-2-deferred" aria-label="Permalink to &quot;H-01 `api/.htaccess` に DB credentials が平文で記載（repo に含まれる）⚠ **Phase 1+3+4 resolved 2026-04-22 / Phase 2 deferred**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c（repo 閲覧権限ある開発者含む）</li><li><strong>対象</strong>: <code>meal.posla.jp(正)/api/.htaccess:3-6</code></li><li><strong>実測</strong>: <code>SetEnv POSLA_DB_PASS odah_eat-posla</code> が正本 repo に<strong>実値</strong>で格納</li><li><strong>Web 露出</strong>: <code>curl /api/.htaccess</code> → HTTP 403（apache FilesMatch で保護）なので<strong>外部公開は防御済</strong></li><li><strong>残リスク</strong>: repo access 権限者（協業者・今後入る人）に DB 認証情報が全公開</li></ul><h4 id="解消内容-phase-1-repo-衛生化、runtime-停止なし" tabindex="-1">解消内容（Phase 1: repo 衛生化、runtime 停止なし） <a class="header-anchor" href="#解消内容-phase-1-repo-衛生化、runtime-停止なし" aria-label="Permalink to &quot;解消内容（Phase 1: repo 衛生化、runtime 停止なし）&quot;">​</a></h4><ol><li><strong>NEW</strong> <code>meal.posla.jp(正)/api/.htaccess.example</code> — placeholder values のテンプレート、commit 対象（新規 dev セットアップ手順を明記）</li><li><strong>EDIT</strong> <code>.gitignore</code> に <code>api/.htaccess</code> 追加 — 以後の commit で credentials 混入を遮断</li><li><code>git rm --cached api/.htaccess</code> — git index から除外（ファイル実体は local dev 用に残置、untracked）</li><li><strong>NO CHANGE</strong>: server <code>/home/odah/www/eat-posla/api/.htaccess</code> — production env var 供給源、連続稼働</li><li><strong>NO CHANGE</strong>: <code>api/config/database.php</code> fallback 値 — 別スライスで placeholder 化予定（env 必須化による runtime リスク回避）</li></ol><h4 id="production-非回帰-実測" tabindex="-1">production 非回帰（実測） <a class="header-anchor" href="#production-非回帰-実測" aria-label="Permalink to &quot;production 非回帰（実測）&quot;">​</a></h4><ul><li><code>GET /api/monitor/ping.php</code> → <code>{&quot;ok&quot;:true,&quot;db&quot;:&quot;ok&quot;}</code> DB 接続健全性維持</li><li>Critical 3（C-01/C-02/C-03）全て 403 維持</li><li>HSTS / login rate-limit / Connect callback CSRF 全て不変</li></ul><h4 id="phase-3-2026-04-22-午後-sakura-db-password-rotation-✅-resolved" tabindex="-1">Phase 3（2026-04-22 午後）: Sakura DB password rotation ✅ resolved <a class="header-anchor" href="#phase-3-2026-04-22-午後-sakura-db-password-rotation-✅-resolved" aria-label="Permalink to &quot;Phase 3（2026-04-22 午後）: Sakura DB password rotation ✅ resolved&quot;">​</a></h4><ul><li>MySQL 8.0.44 の <code>odah_eat-posla@%</code> に対し <code>SET PASSWORD = &#39;&lt;new&gt;&#39;</code> で rotation 実行</li><li>新 password: 48 hex chars（<code>bin2hex(random_bytes(24))</code> で server 上生成、shell-safe）</li><li>旧 password <code>odah_eat-posla</code> は production DB 上で無効化確認（ERROR 1045 Access denied）</li><li>新 password は server <code>/home/odah/www/eat-posla/api/.htaccess</code> + local untracked <code>meal.posla.jp(正)/api/.htaccess</code> の 2 箇所にのみ保管（chmod 604 / 400）</li><li><strong>production 非回帰</strong>: <code>/api/monitor/ping.php</code> → <code>{&quot;ok&quot;:true,&quot;db&quot;:&quot;ok&quot;}</code> 継続、Critical 3 / HSTS / login rate-limit / Connect callback 全て不変</li><li>不整合ウィンドウ: <code>SET PASSWORD</code> と <code>mv .htaccess.new</code> の間 ~1 秒、実測で production ping は成功応答</li><li>docs / scripts/output / bash history / chat log いずれにも新 password 平文を残さない（MYSQL_PWD env var + 直接 sed 経由で処理）</li><li>backup: <code>_backup_20260422_h01_rot/htaccess-pre-rotation.txt</code>（旧 <code>.htaccess</code>）+ <code>rotation-record.txt</code>（タイムスタンプのみ、password なし）</li></ul><h4 id="phase-4-2026-04-22-午後-database-php-fallback-placeholder-化-✅-resolved" tabindex="-1">Phase 4（2026-04-22 午後）: <code>database.php</code> fallback placeholder 化 ✅ resolved <a class="header-anchor" href="#phase-4-2026-04-22-午後-database-php-fallback-placeholder-化-✅-resolved" aria-label="Permalink to &quot;Phase 4（2026-04-22 午後）: `database.php` fallback placeholder 化 ✅ resolved&quot;">​</a></h4><ul><li><code>meal.posla.jp(正)/api/config/database.php</code> の fallback 値を <code>&#39;odah_eat-posla&#39;</code> / <code>&#39;mysql80.odah.sakura.ne.jp&#39;</code> から <code>&#39;&#39;</code> へ変更（4 key × 2 branch = 8 箇所）</li><li>コメント内の <code>POSLA_DB_PASS odah_eat-posla</code> 2 件を <code>&lt;your-rotated-password&gt;</code> placeholder に変更</li><li>header comment の <code>POSLA_DB_NAME=odah_eat-posla</code> / <code>POSLA_DB_USER=odah_eat-posla</code> は DB <strong>名</strong>と <strong>username</strong> への legitimate 言及として残置（Sakura 慣例の identifier、password ではない）</li><li>env var 未設定時は <code>&#39;&#39;</code> で connection 失敗 → サイレント稼働せず明示的エラー</li><li><code>php -l</code> OK</li><li><strong>git tracking 状態</strong>: <code>meal.posla.jp(正)/api/config/database.php</code> は <code>.gitignore:14</code> で ignore 設定済、<code>git ls-files</code> 空で <strong>tracked ではない</strong>。従って今回の placeholder 化は <strong>local 作業コピー限りの変更</strong>で、repo 履歴（HEAD/過去 commit）には影響しない</li></ul><h4 id="⚠-例外メモ-local-server-同一性の一時的乖離-2026-04-22-時点" tabindex="-1">⚠ 例外メモ: local / server 同一性の一時的乖離（2026-04-22 時点） <a class="header-anchor" href="#⚠-例外メモ-local-server-同一性の一時的乖離-2026-04-22-時点" aria-label="Permalink to &quot;⚠ 例外メモ: local / server 同一性の一時的乖離（2026-04-22 時点）&quot;">​</a></h4><p>今回 Phase 4 は <strong>local 側のみ placeholder 化</strong>し、server <code>/home/odah/www/eat-posla/api/config/database.php</code> は touch していない。両ファイルは独立した gitignored copy であり、内容が一時的に異なる:</p><table tabindex="0"><thead><tr><th>location</th><th>fallback 値</th><th>runtime 影響</th></tr></thead><tbody><tr><td>local <code>meal.posla.jp(正)/api/config/database.php</code></td><td><code>&#39;&#39;</code> placeholder</td><td>local dev は POSLA_ENV=local 分岐で docker-compose env var を読む、fallback は発火しない</td></tr><tr><td>server <code>/home/odah/www/eat-posla/api/config/database.php</code></td><td><code>&#39;mysql80.odah...&#39;</code> / <code>&#39;odah_eat-posla&#39;</code>（旧 pw 含む）のまま</td><td>production は .htaccess SetEnv 経由で新 pw を供給、fallback は発火しない（envOr は env var 優先）</td></tr></tbody></table><p><strong>security 観点</strong>: server 側 fallback の旧 password <code>odah_eat-posla</code> は <strong>既に Sakura DB で失効</strong>しているため、仮に fallback が万一発火しても Access denied で即失敗する。<strong>機能上の差分も security blocker も無い</strong>。</p><p><strong>将来の正規化</strong>: 次回 api/ 系の通常デプロイで server の database.php も placeholder 版に揃える（単純上書き）。env var が既に正しく供給されているので runtime 影響なし。</p><ul><li><strong>production 非回帰</strong>: <code>/api/monitor/ping.php</code> → <code>db:&quot;ok&quot;</code> 継続</li></ul><h4 id="phase-2-履歴-cleanup-別スライス保留" tabindex="-1">Phase 2（履歴 cleanup）: 別スライス保留 <a class="header-anchor" href="#phase-2-履歴-cleanup-別スライス保留" aria-label="Permalink to &quot;Phase 2（履歴 cleanup）: 別スライス保留&quot;">​</a></h4><ul><li><strong>理由</strong>: <code>git filter-repo</code> は force-push と既存 clone への影響調整が必要、別 slice で実施</li><li><strong>重要</strong>: rotation 済なので、commit <code>57f3848</code> に残っている旧 credential は既に<strong>無効化済</strong>。漏洩リスクの severity は大幅低下</li><li><strong>前提条件</strong>: runtime secret rotation は Phase 3 で完了（Phase 2 の blocker 解除）</li></ul><h4 id="他の-odah-eat-posla-文字列が含まれる-tracked-ファイル-別論点" tabindex="-1">他の <code>odah_eat-posla</code> 文字列が含まれる tracked ファイル（別論点） <a class="header-anchor" href="#他の-odah-eat-posla-文字列が含まれる-tracked-ファイル-別論点" aria-label="Permalink to &quot;他の `odah_eat-posla` 文字列が含まれる tracked ファイル（別論点）&quot;">​</a></h4><ul><li><p><code>docker-compose.yml</code> / <code>docker/README.md</code> / <code>docker/db/init/01-schema.sh</code> — Docker local dev 用、DB 名と<strong>旧 password が同値</strong>だったため Docker ローカル環境は rotation で影響。local dev 再セットアップ時は .htaccess.example / docker-compose.override.yml で新 password を提供</p></li><li><p><code>docs/manual/internal/**.md</code> + <code>public/docs-internal/**.html</code> + <code>scripts/output/helpdesk-prompt-internal.txt</code> — DB <strong>名</strong>（<code>odah_eat-posla</code>）への言及、password として同値だった Sakura の慣例を記録。旧 password 言及は <strong>docs 更新時に placeholder 化推奨</strong>（別スライス）</p></li><li><p><code>sql/migration-*.sql</code> — 主に DB 名言及、password は含まれない想定（grep 確認は別スライス）</p></li><li><p><strong>確信度</strong>: 高（rotation + placeholder 化 + 非回帰確認すべて完了。Phase 2 は security 実害 mitigated 後の衛生化として別スライス実施）</p></li></ul><h3 id="h-02-api-auth-login-php-に-brute-force-rate-limit-なし-✅-resolved-2026-04-21" tabindex="-1">H-02 <code>api/auth/login.php</code> に brute force rate limit なし ✅ <strong>resolved 2026-04-21</strong> <a class="header-anchor" href="#h-02-api-auth-login-php-に-brute-force-rate-limit-なし-✅-resolved-2026-04-21" aria-label="Permalink to &quot;H-02 `api/auth/login.php` に brute force rate limit なし ✅ **resolved 2026-04-21**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c</li><li><strong>対象</strong>: <code>api/auth/login.php</code> 全体</li><li><strong>解消内容</strong>: <code>require_once &#39;../lib/rate-limiter.php&#39;</code> + <code>check_rate_limit(&#39;login&#39;, 10, 300);</code> を <code>require_method([&#39;POST&#39;]);</code> 直後に追加（1IP あたり 10 回 / 5 分）</li><li><strong>非回帰確認（production 実測）</strong>: GET → 405 / POST 空 body → 400 MISSING_FIELDS / POST 不在 user → 401 INVALID_CREDENTIALS、既存 response 形式不変</li><li><strong>未対応</strong>: 失敗時 <code>write_audit_log</code> での brute force 追跡（別スライス候補）</li><li><strong>backup</strong>: <code>_backup_20260421_highfix/login.php</code></li></ul><h3 id="h-03-15-customer-endpoint-で-rate-limit-未適用-✅-resolved-2026-04-22-webhook-1-件を設計上意図除外" tabindex="-1">H-03 15+ customer endpoint で rate-limit 未適用 ✅ <strong>resolved 2026-04-22（webhook 1 件を設計上意図除外）</strong> <a class="header-anchor" href="#h-03-15-customer-endpoint-で-rate-limit-未適用-✅-resolved-2026-04-22-webhook-1-件を設計上意図除外" aria-label="Permalink to &quot;H-03 15+ customer endpoint で rate-limit 未適用 ✅ **resolved 2026-04-22（webhook 1 件を設計上意図除外）**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: <code>api/customer/*.php</code> 全件</li></ul><h4 id="phase-1-2026-04-22-午前、6-件-ブルート-dos-高リスク" tabindex="-1">Phase 1（2026-04-22 午前、6 件）: ブルート/DoS 高リスク <a class="header-anchor" href="#phase-1-2026-04-22-午前、6-件-ブルート-dos-高リスク" aria-label="Permalink to &quot;Phase 1（2026-04-22 午前、6 件）: ブルート/DoS 高リスク&quot;">​</a></h4><ul><li><code>validate-token.php</code>: 60/300（ポーリング想定）</li><li><code>receipt-view.php</code>: 20/300（payment_id ブルート、30 分 TTL 窓内）</li><li><code>get-bill.php</code>: 30/300（session_token 推測）</li><li><code>satisfaction-rating.php</code>: 10/300（評価スパム / low_rating Push 詐称）</li><li><code>takeout-payment.php</code>: 30/300（決済確認ポーリング濫用）</li><li><code>checkout-session.php</code>: 10/300（Checkout Session 大量作成 DoS）</li></ul><h4 id="phase-2-2026-04-22-午後、8-件-残-customer-endpoint" tabindex="-1">Phase 2（2026-04-22 午後、8 件）: 残 customer endpoint <a class="header-anchor" href="#phase-2-2026-04-22-午後、8-件-残-customer-endpoint" aria-label="Permalink to &quot;Phase 2（2026-04-22 午後、8 件）: 残 customer endpoint&quot;">​</a></h4><ul><li><code>menu.php</code>: 60/300 / <code>order-history.php</code>: 30/300 / <code>checkout-confirm.php</code>: 20/300 / <code>order-status.php</code>: 60/300 / <code>reservation-availability.php</code>: 30/300 / <code>reservation-detail.php</code>: 30/300 / <code>reservation-precheckin.php</code>: 30/300 / <code>ui-translations.php</code>: 60/300</li></ul><h4 id="意図的除外-1-件" tabindex="-1">意図的除外 1 件 <a class="header-anchor" href="#意図的除外-1-件" aria-label="Permalink to &quot;意図的除外 1 件&quot;">​</a></h4><ul><li><code>reservation-deposit-webhook.php</code>: Stripe webhook。<code>verify_webhook_signature()</code> HMAC で保護、rate-limit は legitimate retry を壊す副作用が大きい</li></ul><h4 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h4><ul><li><code>reservation-update.php</code> は audit 時点で既に適用済（line 16 に <code>check_rate_limit(&#39;reserve-update:&#39; . IP, 10, 60)</code>）。Agent D 指摘が 1 件過大だった</li><li>適用済 customer endpoint: <strong>25 / 26</strong>（webhook 1 件意図的除外）</li></ul><h4 id="production-実測-phase-2" tabindex="-1">production 実測（Phase 2） <a class="header-anchor" href="#production-実測-phase-2" aria-label="Permalink to &quot;production 実測（Phase 2）&quot;">​</a></h4><p>各 endpoint 正常応答（200/400/403/404）、50x なし、既存バリデーション不変</p><ul><li><strong>backup</strong>: <code>_backup_20260422_hardening/</code>（Phase 1）、<code>_backup_20260422_h034_14/</code>（Phase 2）</li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-04-post-api-群で-csrf-対策が-samesite-lax-のみ-⚠-partial-resolved-2026-04-22-admin-state-changing-subset-閉じる" tabindex="-1">H-04 POST API 群で CSRF 対策が SameSite=Lax のみ ⚠ <strong>partial-resolved 2026-04-22（admin state-changing subset 閉じる）</strong> <a class="header-anchor" href="#h-04-post-api-群で-csrf-対策が-samesite-lax-のみ-⚠-partial-resolved-2026-04-22-admin-state-changing-subset-閉じる" aria-label="Permalink to &quot;H-04 POST API 群で CSRF 対策が SameSite=Lax のみ ⚠ **partial-resolved 2026-04-22（admin state-changing subset 閉じる）**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c</li><li><strong>対象</strong>: <code>api/store/**.php</code> POST / <code>api/customer/*.php</code> POST</li></ul><h4 id="phase-1-2026-04-22-午前-helper-追加-1-endpoint-適用" tabindex="-1">Phase 1（2026-04-22 午前）: helper 追加 + 1 endpoint 適用 <a class="header-anchor" href="#phase-1-2026-04-22-午前-helper-追加-1-endpoint-適用" aria-label="Permalink to &quot;Phase 1（2026-04-22 午前）: helper 追加 + 1 endpoint 適用&quot;">​</a></h4><ul><li><code>api/lib/auth.php</code> に新 helper <code>verify_origin()</code>。Origin 優先、Referer fallback、両方なしは通過（curl / サーバー間連携対応）、不一致は <code>FORBIDDEN_ORIGIN</code> 403</li><li><code>api/owner/users.php</code> DELETE に opt-in 適用</li></ul><h4 id="phase-2-2026-04-22-午後-admin-state-changing-6-endpoint-に拡張" tabindex="-1">Phase 2（2026-04-22 午後）: admin state-changing 6 endpoint に拡張 <a class="header-anchor" href="#phase-2-2026-04-22-午後-admin-state-changing-6-endpoint-に拡張" aria-label="Permalink to &quot;Phase 2（2026-04-22 午後）: admin state-changing 6 endpoint に拡張&quot;">​</a></h4><p>追加 opt-in 適用:</p><ul><li><code>api/store/payment-void.php</code> POST（金銭、require_auth の前に verify_origin）</li><li><code>api/store/refund-payment.php</code> POST（金銭、require_role の前に verify_origin）</li><li><code>api/store/emergency-payment-transfer.php</code> POST（緊急会計→payments 転記）</li><li><code>api/store/emergency-payment-manual-transfer.php</code> POST（手入力売上計上）</li><li><code>api/owner/users.php</code> POST（user 作成）</li><li><code>api/owner/users.php</code> PATCH（user 更新）</li></ul><p>合計適用 endpoint: <strong>7 箇所</strong>（DELETE 既存含む）</p><h4 id="production-実測-悪意-origin-spoof-テスト" tabindex="-1">production 実測（悪意 Origin spoof テスト） <a class="header-anchor" href="#production-実測-悪意-origin-spoof-テスト" aria-label="Permalink to &quot;production 実測（悪意 Origin spoof テスト）&quot;">​</a></h4><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /api/store/payment-void.php  + Origin: attacker.example.com → 403 FORBIDDEN_ORIGIN ✅</span></span>\n<span class="line"><span>POST /api/store/refund-payment.php + Origin: attacker.example.com → 403 FORBIDDEN_ORIGIN ✅</span></span>\n<span class="line"><span>POST /api/owner/users.php + Origin: attacker.example.com → 401（require_role 先行、設計通り）</span></span>\n<span class="line"><span>POST /api/store/payment-void.php + Origin: eat.posla.jp → 401 UNAUTHORIZED（auth で弾く、正常）</span></span></code></pre></div><p>CSRF 攻撃経路（authenticated session + attacker.com Origin）は全て 403 で遮断される設計。</p><h4 id="残り-別スライス" tabindex="-1">残り（別スライス） <a class="header-anchor" href="#残り-別スライス" aria-label="Permalink to &quot;残り（別スライス）&quot;">​</a></h4><ul><li><p>全 customer POST / PATCH 自動適用: 既存 QR / PIN 経路の Origin 付与有無の互換性テスト要、別スライス</p></li><li><p>全 emergency-payment 系（残 5 件）への適用: 同様の opt-in で次スライス可能</p></li><li><p>SameSite=Lax → Strict 変更: owner-dashboard の外部開き動線への影響確認要</p></li><li><p><strong>backup</strong>: <code>_backup_20260422_hardening/</code>（Phase 1）、<code>_backup_20260422_h034_14/</code>（Phase 2）</p></li><li><p><strong>確信度</strong>: 高</p></li></ul><h3 id="h-05-session-token-qr-トークンに-rotation-ip-pinning-なし-⚠-deferred-2026-04-22-別スライス、staging-必須" tabindex="-1">H-05 session_token / QR トークンに rotation / IP pinning なし ⚠ <strong>deferred 2026-04-22（別スライス、staging 必須）</strong> <a class="header-anchor" href="#h-05-session-token-qr-トークンに-rotation-ip-pinning-なし-⚠-deferred-2026-04-22-別スライス、staging-必須" aria-label="Permalink to &quot;H-05 session_token / QR トークンに rotation / IP pinning なし ⚠ **deferred 2026-04-22（別スライス、staging 必須）**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: <code>api/customer/table-session.php</code> / 各 api/customer の session_token 検証</li><li><strong>現状</strong>: <code>bin2hex(random_bytes(16))</code> で 128bit エントロピー、TTL 4 時間、rotation なし、IP / User-Agent pinning なし</li><li><strong>想定被害</strong>: QR 撮影 / 同 Wi-Fi の盗聴で session_token 取得 → 別端末から 4 時間利用可</li><li><strong>deferred 理由</strong>: H-06 / H-13 と一緒に処理するには影響範囲が大きい <ul><li>schema 追加: <code>tables.session_token_seen_ua</code> / <code>session_token_seen_ip</code> / <code>session_token_last_used_at</code></li><li>app 変更: <code>api/customer/*.php</code> の session_token 検証 10+ endpoint に pinning ロジック</li><li>UX 影響: QR 経由顧客の別端末タップで session 切断される可能性（相席 / 家族間 QR 共有の挙動再定義が必要）</li><li>運用: rotation で「古いタブ」が突如 403 になる挙動の tenant 向け docs 説明が必要</li></ul></li><li><strong>推奨 sub-slice 分割</strong>: <ul><li>Phase 1: schema 追加のみ（columns 追加、app は未使用 = no-op）</li><li>Phase 2: 最初のアクセス時に UA/IP を記録（観測のみ、拒否しない）</li><li>Phase 3: 不一致時の 403 拒否（staging 相当環境で QR / 相席 / 長時間滞在を回帰テスト）</li><li>Phase 4: 毎 POST で token rotation（最も影響大、慎重に）</li></ul></li><li><strong>確信度</strong>: 高（仕様設計 + staging 必須）</li></ul><h3 id="h-06-audit-log-テーブルが-append-only-化されていない-✅-resolved-2026-04-22" tabindex="-1">H-06 audit_log テーブルが append-only 化されていない ✅ <strong>resolved 2026-04-22</strong> <a class="header-anchor" href="#h-06-audit-log-テーブルが-append-only-化されていない-✅-resolved-2026-04-22" aria-label="Permalink to &quot;H-06 audit_log テーブルが append-only 化されていない ✅ **resolved 2026-04-22**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: b（DB 直叩き可能な悪意ある admin）</li><li><strong>対象</strong>: <code>audit_log</code> テーブル（DB schema）</li><li><strong>解消内容</strong>: <ul><li>NEW <code>sql/migration-h06-audit-log-append-only.sql</code> を作成・production 適用</li><li><code>audit_log_no_update</code> BEFORE UPDATE trigger で <code>SIGNAL SQLSTATE &#39;45000&#39;</code> 発行</li><li><code>audit_log_no_delete</code> BEFORE DELETE trigger で同様</li><li>app 層は INSERT のみ使用、runtime 影響なし（既存 <code>audit-log.php</code> / CP1 / 4d-5 系の INSERT 路線は不変）</li></ul></li><li><strong>production 実測（2026-04-22、本番影響は管理可能な最小限）</strong>: <ul><li>INSERT → 成功（id=1060 付与、<code>tenant_id=&#39;h06-test&#39;</code> で test row を 1 件追加）</li><li>UPDATE → <strong>ERROR 1644 (45000): audit_log is append-only: UPDATE denied (H-06)</strong> ✅</li><li>DELETE → <strong>ERROR 1644 (45000): audit_log is append-only: DELETE denied (H-06)</strong> ✅</li><li>1,059 既存 rows 不変、append されたのは test row 1 件のみ</li></ul></li><li><strong>rollback</strong>: <code>DROP TRIGGER IF EXISTS audit_log_no_update; DROP TRIGGER IF EXISTS audit_log_no_delete;</code></li><li><strong>test 痕跡</strong>: id=1060 / <code>tenant_id=&#39;h06-test&#39;</code> / <code>action=&#39;test_insert&#39;</code> の 1 行が audit_log に<strong>意図的に残存</strong>（trigger invariant「一度書いたら消えない」を守るため cleanup しない、test tag で識別可）</li><li><strong>将来 cleanup</strong>: GDPR 等で legitimate delete が必要な場合、rollback SQL で trigger 外して cleanup 後 reapply</li><li><strong>backup</strong>: <code>_backup_20260422_h06_h13/audit_log_backup.tsv</code>（1,059 rows の TSV 形式 snapshot）</li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-07-tenants-stripe-secret-key-が-db-平文保存" tabindex="-1">H-07 <code>tenants.stripe_secret_key</code> が DB 平文保存 <a class="header-anchor" href="#h-07-tenants-stripe-secret-key-が-db-平文保存" aria-label="Permalink to &quot;H-07 `tenants.stripe_secret_key` が DB 平文保存&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: b（DB dump 奪取）</li><li><strong>対象</strong>: <code>sql/schema.sql</code> の <code>tenants</code> テーブル</li><li><strong>現状</strong>: Stripe secret key が平文 VARCHAR で保存、KMS / アプリ層暗号化なし</li><li><strong>想定被害</strong>: DB backup / dump が漏れた時点で全テナントの Stripe 決済乗っ取り可能</li><li><strong>修正</strong>: <ul><li>短期: DB backup を暗号化 + backup permission 最小化</li><li>中期: <code>openssl_encrypt</code> で platform key 暗号化 + env 変数で復号 key</li><li>長期: Pattern B（Stripe Connect）に統一し <code>stripe_connect_account_id</code> のみ保持、secret key は platform 側のみ</li></ul></li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-08-web-push-vapid-秘密鍵が-posla-settings-に平文保存" tabindex="-1">H-08 Web Push VAPID 秘密鍵が <code>posla_settings</code> に平文保存 <a class="header-anchor" href="#h-08-web-push-vapid-秘密鍵が-posla-settings-に平文保存" aria-label="Permalink to &quot;H-08 Web Push VAPID 秘密鍵が `posla_settings` に平文保存&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c（POSLA admin 奪取）</li><li><strong>対象</strong>: <code>posla_settings.setting_value</code> where <code>setting_key=&#39;web_push_vapid_private_pem&#39;</code></li><li><strong>現状</strong>: PEM 平文、約 241 char</li><li><strong>想定被害</strong>: 全テナントの push 通知を詐称、phishing 配布</li><li><strong>修正</strong>: H-07 と同じ方針。短期は POSLA admin の 2FA + session IP 固定</li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-09-idempotency-key-がクライアント生成-予測可能" tabindex="-1">H-09 <code>idempotency_key</code> がクライアント生成（予測可能） <a class="header-anchor" href="#h-09-idempotency-key-がクライアント生成-予測可能" aria-label="Permalink to &quot;H-09 `idempotency_key` がクライアント生成（予測可能）&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: b</li><li><strong>対象</strong>: <code>api/customer/orders.php</code> 等で client が生成した <code>idempotency_key</code> を信頼</li><li><strong>現状</strong>: 値の検証は UNIQUE 制約のみ、client が <code>&quot;1&quot;</code> <code>&quot;2&quot;</code> などで送ると conflict が発生</li><li><strong>想定被害</strong>: 他顧客の idempotency_key と衝突させて注文失敗を誘発 / 注文履歴推測</li><li><strong>修正</strong>: server 側で UUID を自動付与、client 側送信は「再送重複チェック用ヒント」扱いに変更</li><li><strong>確信度</strong>: 中</li></ul><h3 id="h-10-api-connect-callback-php-に-state-parameter-hmac-なし-csrf-✅-resolved-2026-04-22" tabindex="-1">H-10 <code>api/connect/callback.php</code> に state parameter / HMAC なし（CSRF）✅ <strong>resolved 2026-04-22</strong> <a class="header-anchor" href="#h-10-api-connect-callback-php-に-state-parameter-hmac-なし-csrf-✅-resolved-2026-04-22" aria-label="Permalink to &quot;H-10 `api/connect/callback.php` に state parameter / HMAC なし（CSRF）✅ **resolved 2026-04-22**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c</li><li><strong>対象</strong>: <code>api/connect/callback.php:15</code></li><li><strong>解消内容</strong>: <ul><li><code>api/connect/onboard.php</code>: <code>require_role(&#39;owner&#39;)</code> で既にアクティブな session に <code>bin2hex(random_bytes(16))</code> で 32 桁 state token を発行、<code>$_SESSION[&#39;connect_state_&#39; . $tenantId]</code> に保存、callback URL の <code>state</code> param に付与</li><li><code>api/connect/callback.php</code>: <code>start_auth_session()</code> で session 継続、<code>$_GET[&#39;state&#39;]</code> と session 値を <code>hash_equals</code> 照合、失敗時は owner-dashboard へ <code>connect=state_error</code> でリダイレクト、成功時は session から state を削除（one-time use）</li></ul></li><li><strong>production 実測</strong>: <ul><li>state なし → HTTP 302 Location: <code>.../connect=state_error</code> ✅</li><li>偽造 state → HTTP 302 Location: <code>.../connect=state_error</code> ✅</li><li>CSRF <code>&lt;img src=&quot;...callback.php?tenant_id=X&quot;&gt;</code> 経路は state 検証で完全遮断</li></ul></li><li><strong>backup</strong>: <code>_backup_20260422_hardening/connect-callback.php</code> / <code>connect-onboard.php</code></li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-11-hsts-ヘッダが未設定-✅-resolved-2026-04-21" tabindex="-1">H-11 HSTS ヘッダが未設定 ✅ <strong>resolved 2026-04-21</strong> <a class="header-anchor" href="#h-11-hsts-ヘッダが未設定-✅-resolved-2026-04-21" aria-label="Permalink to &quot;H-11 HSTS ヘッダが未設定 ✅ **resolved 2026-04-21**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: 全 HTTPS 応答</li><li><strong>解消内容</strong>: NEW <code>meal.posla.jp(正)/.htaccess</code> に <code>&lt;IfModule mod_headers.c&gt;</code> 内で <code>Header always set Strict-Transport-Security &quot;max-age=31536000; includeSubDomains&quot;</code> を配置（preload なし）</li><li><strong>production 実測</strong>: <code>/</code> / <code>/public/admin/index.html</code> / <code>/api/auth/me.php</code> / <code>/api/auth/login.php</code> / <code>/public/docs-tenant/</code> / <code>/api/customer/menu.php</code> の全 6 URL で <code>strict-transport-security: max-age=31536000; includeSubDomains</code> が header に付与確認</li><li><strong>未対応</strong>: preload list 登録（恒久対策側で判断）</li><li><strong>backup</strong>: 不要（新規 .htaccess 追加のみ）</li></ul><h3 id="h-12-api-owner-users-php-の-delete-権限境界が未確認-✅-resolved-2026-04-22-誤検知確定" tabindex="-1">H-12 <code>api/owner/users.php</code> の DELETE 権限境界が未確認 ✅ <strong>resolved 2026-04-22（誤検知確定）</strong> <a class="header-anchor" href="#h-12-api-owner-users-php-の-delete-権限境界が未確認-✅-resolved-2026-04-22-誤検知確定" aria-label="Permalink to &quot;H-12 `api/owner/users.php` の DELETE 権限境界が未確認 ✅ **resolved 2026-04-22（誤検知確定）**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: c</li><li><strong>対象</strong>: <code>api/owner/users.php</code> DELETE handler</li><li><strong>検証結果（実コード read）</strong>: <strong>境界は完全防御済</strong>。DELETE handler（line 302-336）が以下を実装: <ul><li>line 305: <code>CANNOT_DELETE_SELF</code> — 自己削除防止</li><li>line 307: <code>WHERE id = ? AND tenant_id = ?</code> — テナント境界</li><li>line 313-323: manager の場合、<code>role === &#39;staff&#39;</code> 以外は 403、さらに <code>user_stores.store_id</code> の交差確認（P1b-1 で追加）</li></ul></li><li><strong>判定</strong>: Agent B の「未検証」指摘は実コード未読の推測。tenant owner が自己組織内の owner/manager/staff を削除できる仕様は妥当（POSLA admin と tenant owner は別レイヤー）</li><li><strong>追加 hardening</strong>: H-04 の <code>verify_origin()</code> opt-in 適用で CSRF 層を追加</li><li><strong>確信度</strong>: 高（実コード読破）</li></ul><h3 id="h-13-stripe-external-payment-id-に-unique-制約なし-✅-resolved-2026-04-22" tabindex="-1">H-13 Stripe <code>external_payment_id</code> に UNIQUE 制約なし ✅ <strong>resolved 2026-04-22</strong> <a class="header-anchor" href="#h-13-stripe-external-payment-id-に-unique-制約なし-✅-resolved-2026-04-22" aria-label="Permalink to &quot;H-13 Stripe `external_payment_id` に UNIQUE 制約なし ✅ **resolved 2026-04-22**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: b（race 条件悪用）</li><li><strong>対象</strong>: <code>payments.external_payment_id</code> column</li><li><strong>現物確認（2026-04-22）</strong>: <ul><li>17 payments に ext_id 設定、17 distinct → <strong>duplicate 0 件</strong> ✅</li><li>100 payments は NULL（cash / 手動 card / qr）</li></ul></li><li><strong>解消内容</strong>: <ul><li>NEW <code>sql/migration-h13-payments-ext-id-unique.sql</code> を作成・production 適用</li><li><code>ALTER TABLE payments ADD UNIQUE KEY uq_external_payment_id (external_payment_id)</code></li><li>MySQL InnoDB の UNIQUE は複数 NULL を許容、cash/manual 100 件に影響なし</li></ul></li><li><strong>production 実測（2026-04-22）</strong>: <ul><li><code>SHOW INDEX FROM payments</code> で <code>uq_external_payment_id</code> 追加確認</li><li>既存 17 rows duplicate violation なし（cardinality=18 で正常）</li><li>同一 ext_id で 2 回 INSERT → 2 回目 <strong>ERROR 1062 Duplicate entry &#39;pi_TEST_UNIQ_H13&#39; for key &#39;payments.uq_external_payment_id&#39;</strong> ✅</li><li>test row は cleanup 済（remaining=0）</li><li>NULL は複数許容（cash/manual 100 件継続）</li></ul></li><li><strong>app 層の挙動</strong>: <ul><li><code>checkout-confirm.php:179-190</code> / <code>takeout-payment.php</code> の早期 idempotent return は維持（DB 到達前に重複検出、既存 UX 維持）</li><li>DB UNIQUE は TOCTOU race で app 層を擦り抜けた 2 並列 INSERT を最終防御層として弾く</li></ul></li><li><strong>rollback</strong>: <code>ALTER TABLE payments DROP INDEX uq_external_payment_id;</code></li><li><strong>backup</strong>: <code>_backup_20260422_h06_h13/payments_ext_id_backup.tsv</code>（17 rows snapshot）</li><li><strong>確信度</strong>: 高</li></ul><h3 id="h-14-エラー応答に内部情報が混入する経路-⚠-partial-resolved-2026-04-22-public-non-admin-subset-解消" tabindex="-1">H-14 エラー応答に内部情報が混入する経路 ⚠ <strong>partial-resolved 2026-04-22（public/non-admin subset 解消）</strong> <a class="header-anchor" href="#h-14-エラー応答に内部情報が混入する経路-⚠-partial-resolved-2026-04-22-public-non-admin-subset-解消" aria-label="Permalink to &quot;H-14 エラー応答に内部情報が混入する経路 ⚠ **partial-resolved 2026-04-22（public/non-admin subset 解消）**&quot;">​</a></h3><ul><li><strong>攻撃者</strong>: a</li><li><strong>対象</strong>: 多数の <code>json_error(&#39;DB_ERROR&#39;, &#39;...&#39;, 500)</code></li></ul><h4 id="phase-1-php-レベル遮断-2026-04-22-午前" tabindex="-1">Phase 1: PHP レベル遮断（2026-04-22 午前） <a class="header-anchor" href="#phase-1-php-レベル遮断-2026-04-22-午前" aria-label="Permalink to &quot;Phase 1: PHP レベル遮断（2026-04-22 午前）&quot;">​</a></h4><ul><li>root <code>.htaccess</code> に PHP エラー設定を明示: <code>php_flag display_errors Off</code> / <code>php_flag log_errors On</code> / <code>php_flag display_startup_errors Off</code></li><li><code>mod_php</code> / <code>mod_php7</code> / <code>mod_php8</code> の 3 パターンで <code>&lt;IfModule&gt;</code> 分岐（Sakura 環境依存吸収）</li><li>PHP 自体の warning / notice / fatal / startup error の browser 表示を遮断</li></ul><h4 id="phase-2-アプリレベル-—-public-non-admin-reachable-6-endpoint-の-getmessage-除去-2026-04-22-午後" tabindex="-1">Phase 2: アプリレベル — public/non-admin reachable 6 endpoint の getMessage 除去（2026-04-22 午後） <a class="header-anchor" href="#phase-2-アプリレベル-—-public-non-admin-reachable-6-endpoint-の-getmessage-除去-2026-04-22-午後" aria-label="Permalink to &quot;Phase 2: アプリレベル — public/non-admin reachable 6 endpoint の getMessage 除去（2026-04-22 午後）&quot;">​</a></h4><p><code>$e-&gt;getMessage()</code> を <code>json_error</code> のメッセージ文字列に連結している 24 箇所のうち、<strong><code>require_auth()</code> or <code>require_role(&#39;staff&#39;)</code> のみで device/staff reachable な 6 endpoint</strong> を優先修正:</p><table tabindex="0"><thead><tr><th>#</th><th>endpoint</th><th>role 境界</th><th>既存 error_log</th><th>対応</th></tr></thead><tbody><tr><td>1</td><td><code>api/kds/orders.php:33</code></td><td><code>require_auth()</code>（device/staff KDS polling 3s 間隔）</td><td>なし</td><td>error_log 追加 + 固定文言</td></tr><tr><td>2</td><td><code>api/kds/close-table.php:137</code></td><td><code>require_auth()</code>（deprecated, device/staff）</td><td>なし</td><td>error_log 追加 + 固定文言</td></tr><tr><td>3</td><td><code>api/store/tables-status.php:30</code></td><td><code>require_auth()</code>（device/staff polling）</td><td>なし</td><td>error_log 追加 + 固定文言</td></tr><tr><td>4</td><td><code>api/store/last-order.php:90</code></td><td><code>require_auth()</code></td><td>なし</td><td>error_log 追加 + 固定文言（migration hint は維持）</td></tr><tr><td>5</td><td><code>api/store/receipt.php:344</code></td><td><code>require_auth()</code>（cashier）</td><td>既存 <code>[L-5 receipt]</code></td><td>既存 error_log 維持、browser message から getMessage 削除</td></tr><tr><td>6</td><td><code>api/store/reservation-seat.php:94</code></td><td><code>require_role(&#39;staff&#39;)</code></td><td>既存 <code>[L-9][reservation-seat]</code></td><td>既存 error_log 維持、browser message から getMessage 削除</td></tr></tbody></table><h4 id="ui-側-caller-安全性確認" tabindex="-1">UI 側 caller 安全性確認 <a class="header-anchor" href="#ui-側-caller-安全性確認" aria-label="Permalink to &quot;UI 側 caller 安全性確認&quot;">​</a></h4><p><code>public/kds/*.js</code> / <code>public/admin/*.js</code> の <code>json.error.message</code> 参照 20 箇所を grep で確認、全て toast 表示 / throw Error の汎用テキストとして利用され、<strong>メッセージ文字列をパースしている caller はゼロ</strong>。固定文言への差し替えは安全。</p><h4 id="production-実測" tabindex="-1">production 実測 <a class="header-anchor" href="#production-実測" aria-label="Permalink to &quot;production 実測&quot;">​</a></h4><p>6 endpoint に対し未認証 GET で 401 / 405 / 400 の期待ガード応答を確認、500 応答での内部情報漏洩経路なし。Critical 3 / HSTS / login rate-limit / Connect CSRF は全て不変。</p><h4 id="phase-3-2026-04-22-午後-admin-only-17-件を解消" tabindex="-1">Phase 3 (2026-04-22 午後): admin-only 17 件を解消 <a class="header-anchor" href="#phase-3-2026-04-22-午後-admin-only-17-件を解消" aria-label="Permalink to &quot;Phase 3 (2026-04-22 午後): admin-only 17 件を解消&quot;">​</a></h4><p>admin 認証済のみ到達可能な subset を一括除去:</p><ul><li><strong>CSV import 8 件</strong>: <code>api/owner/{ingredients,menu,recipes}-csv.php</code> / <code>api/store/{course,local-items,menu-overrides,plan-menu-items,time-limit-plans}-csv.php</code>（全て <code>require_role(&#39;manager&#39;)</code>）</li><li><strong>Emergency payment 7 件</strong>: <code>emergency-payment-{external-method,manual-transfer,manual-void,resolution,transfer-void,transfer}.php</code> / <code>emergency-payments.php</code>（内部で manager|owner role check）</li><li><strong>Admin-like 2 件</strong>: <code>payment-void.php:396</code>（line 76 で manager/owner role 確認）/ <code>shift/help-requests.php:387</code>（line 170 で <code>require_role(&#39;manager&#39;)</code>）</li></ul><p>全 17 件で <code>getMessage()</code> 連結部を削除、<code>error_log()</code> 追加で内部調査性維持。本 subset は UI caller パース依存なしを前 slice で確認済（grep 20 箇所、全て汎用 toast/throw）。</p><h4 id="残り-1-件-意図的除外" tabindex="-1">残り 1 件（意図的除外） <a class="header-anchor" href="#残り-1-件-意図的除外" aria-label="Permalink to &quot;残り 1 件（意図的除外）&quot;">​</a></h4><ul><li><strong><code>api/store/translate-menu.php:90</code></strong>: <code>TranslateMenuException</code> という custom domain exception 経由で <code>$e-&gt;getMessage()</code> を返す。messages は domain-level で user-facing 意図的設計（翻訳エラー詳細を UI に表示する）、raw PDO ではないため内部情報漏洩リスクなし。<strong>今後も除去対象にしない</strong></li></ul><h4 id="production-実測-phase-3" tabindex="-1">production 実測（Phase 3） <a class="header-anchor" href="#production-実測-phase-3" aria-label="Permalink to &quot;production 実測（Phase 3）&quot;">​</a></h4><ul><li><p>全 17 endpoint 未認証 POST → 401/403（既存 auth/role guard 維持）</p></li><li><p>Critical 3 / HSTS / login rate-limit / Connect CSRF 全て不変</p></li><li><p>全体 <code>json_error...getMessage</code> 件数: 24 → <strong>1</strong>（translate-menu のみ、意図的除外）</p></li><li><p><strong>backup</strong>: <code>_backup_20260422_hardening/</code>（Phase 1）、<code>_backup_20260422_h14/</code>（Phase 2 non-admin 6 件）、<code>_backup_20260422_h034_14/</code>（Phase 3 admin-only 17 件）</p></li><li><p><strong>最終確信度</strong>: 高（public/admin 全路線で getMessage 混入解消、残 1 件は意図的 domain exception）</p></li></ul><hr><h2 id="_98-5-medium-—-運用開始後-30-日以内に改善" tabindex="-1">98.5 Medium — 運用開始後 30 日以内に改善 <a class="header-anchor" href="#_98-5-medium-—-運用開始後-30-日以内に改善" aria-label="Permalink to &quot;98.5 Medium — 運用開始後 30 日以内に改善&quot;">​</a></h2><h3 id="m-01-api-kds-update-status-php-が-paid-値を受け付ける" tabindex="-1">M-01 <code>api/kds/update-status.php</code> が <code>&#39;paid&#39;</code> 値を受け付ける <a class="header-anchor" href="#m-01-api-kds-update-status-php-が-paid-値を受け付ける" aria-label="Permalink to &quot;M-01 `api/kds/update-status.php` が `&#39;paid&#39;` 値を受け付ける&quot;">​</a></h3><ul><li><strong>既知</strong>: §9.38 で defense-in-depth 候補として記録済</li><li><strong>対象</strong>: <code>api/kds/update-status.php:30</code> <code>$validStatuses</code> に <code>&#39;paid&#39;</code> 含む</li><li><strong>現状</strong>: UI は送らないが device ロール乗っ取り時に任意 order を paid 化可能（手で POST）</li><li><strong>修正</strong>: <code>$validStatuses</code> から <code>&#39;paid&#39;</code> を削除（cancelled 含む他の終端 status も検討）</li><li><strong>確信度</strong>: 高</li></ul><h3 id="m-02-api-kds-close-table-php-が-deprecated-だが-404-化されていない" tabindex="-1">M-02 <code>api/kds/close-table.php</code> が deprecated だが 404 化されていない <a class="header-anchor" href="#m-02-api-kds-close-table-php-が-deprecated-だが-404-化されていない" aria-label="Permalink to &quot;M-02 `api/kds/close-table.php` が deprecated だが 404 化されていない&quot;">​</a></h3><ul><li><strong>既知</strong>: §9.38</li><li><strong>修正</strong>: ファイル先頭で <code>http_response_code(410); echo &#39;Gone&#39;; exit;</code> を追加</li><li><strong>確信度</strong>: 高</li></ul><h3 id="m-03-scripts-p1-27-generate-torimaru-sample-orders-php-が本番に存在する可能性" tabindex="-1">M-03 <code>scripts/p1-27-generate-torimaru-sample-orders.php</code> が本番に存在する可能性 <a class="header-anchor" href="#m-03-scripts-p1-27-generate-torimaru-sample-orders-php-が本番に存在する可能性" aria-label="Permalink to &quot;M-03 `scripts/p1-27-generate-torimaru-sample-orders.php` が本番に存在する可能性&quot;">​</a></h3><ul><li><strong>既知</strong>: §9.38 で 7,430 件 demo seeder の発生源</li><li><strong>修正</strong>: 本番 deploy 除外 / 実行防止フラグ / 最初に <code>die(&#39;disabled&#39;)</code> を仕込む</li><li><strong>確信度</strong>: 高</li></ul><h3 id="m-04-phone-order-id-enumeration-takeout" tabindex="-1">M-04 phone + order_id enumeration（takeout） <a class="header-anchor" href="#m-04-phone-order-id-enumeration-takeout" aria-label="Permalink to &quot;M-04 phone + order_id enumeration（takeout）&quot;">​</a></h3><ul><li><strong>対象</strong>: <code>api/customer/takeout-orders.php?action=status</code></li><li><strong>想定被害</strong>: phone（10-11 桁）を固定すれば、UUID と組み合わせで他顧客 takeout 状態を覗ける可能性</li><li><strong>修正</strong>: rate-limit 追加（phone hash 単位）+ phone ではなく sms で verify</li><li><strong>確信度</strong>: 中</li></ul><h3 id="m-05〜m-18-省略-別添-scripts-audit-内の-comment-に詳細" tabindex="-1">M-05〜M-18 省略（別添 <code>scripts/audit/</code> 内の comment に詳細） <a class="header-anchor" href="#m-05〜m-18-省略-別添-scripts-audit-内の-comment-に詳細" aria-label="Permalink to &quot;M-05〜M-18 省略（別添 `scripts/audit/` 内の comment に詳細）&quot;">​</a></h3><p>詳細項目:</p><ul><li>M-05: <code>cart-event.php</code> 保存データの consumer 追加時の XSS 露呈リスク</li><li>M-06: <code>places-proxy</code> の tenant-level audit log なし</li><li>M-07: sub-session token の single-use 化未実装</li><li>M-08: rate-limiter file が <code>/tmp</code> 配置で systemd-tmpfiles により reset リスク</li><li>M-09: Open redirect risk（checkout success_url の Host header 信頼）</li><li>M-10: order.items JSON の taxRate 改ざん path（S3#4 で再計算済）</li><li>M-11: receipt orphan（void 後の領収書再印刷）</li><li>M-12: plan_menu_items の store_id 境界検証 agent B 未確認</li><li>M-13: <code>reservation-availability.php</code> 無制限スキャン DoS</li><li>M-14: <code>customer-phone</code> / <code>note</code> の入力 sanitize 強化</li><li>M-15: <code>satisfaction-rating.reason_text</code> 出力側 escape 検証</li><li>M-16: process-payment 同時 POST race（<code>SELECT ... FOR UPDATE</code> 済だが担当 PIN 検証 race）</li><li>M-17: refund-payment claim revert の idempotency</li><li>M-18: push subscription の scope=owner 詐称（P1a / Phase 2b で部分対応済、残存リスク評価）</li></ul><hr><h2 id="_98-6-low-記録のみ、運用で観測・改善" tabindex="-1">98.6 Low（記録のみ、運用で観測・改善） <a class="header-anchor" href="#_98-6-low-記録のみ、運用で観測・改善" aria-label="Permalink to &quot;98.6 Low（記録のみ、運用で観測・改善）&quot;">​</a></h2><ul><li>L-01〜L-10: agent 指摘のうち防御既存 / 実害極小 / 設計上許容のもの（<code>scripts/audit/</code> の各スクリプト comment に記載）</li></ul><hr><h2 id="_98-7-攻撃者モデル別のテストシナリオ" tabindex="-1">98.7 攻撃者モデル別のテストシナリオ <a class="header-anchor" href="#_98-7-攻撃者モデル別のテストシナリオ" aria-label="Permalink to &quot;98.7 攻撃者モデル別のテストシナリオ&quot;">​</a></h2><h3 id="a-外部匿名攻撃者" tabindex="-1">a: 外部匿名攻撃者 <a class="header-anchor" href="#a-外部匿名攻撃者" aria-label="Permalink to &quot;a: 外部匿名攻撃者&quot;">​</a></h3><ol><li>C-01/C-02/C-03 の直接 GET（internal docs / error catalog 入手）</li><li>QR 撮影 → session_token 取得 → 4 時間別端末から注文（H-05）</li><li><code>/api/auth/login.php</code> へ 1 万回 POST（H-02）</li><li>rate-limit なし endpoint の全自動スキャン（H-03）</li></ol><h3 id="b-悪意あるスタッフ-manager" tabindex="-1">b: 悪意あるスタッフ / manager <a class="header-anchor" href="#b-悪意あるスタッフ-manager" aria-label="Permalink to &quot;b: 悪意あるスタッフ / manager&quot;">​</a></h3><ol><li><code>api/store/staff-management.php</code> で他店舗 user への DELETE（既防御）</li><li><code>payments.stripe_secret_key</code> を DB 直接 SELECT（H-07）</li><li>audit_log DELETE / UPDATE（H-06）</li><li><code>M-01</code> device による任意 paid 化</li></ol><h3 id="c-悪意ある他テナント-owner" tabindex="-1">c: 悪意ある他テナント owner <a class="header-anchor" href="#c-悪意ある他テナント-owner" aria-label="Permalink to &quot;c: 悪意ある他テナント owner&quot;">​</a></h3><ol><li><code>api/connect/callback.php?tenant_id=OTHER</code> CSRF（H-10）</li><li>URL パラメータ <code>store_id</code> 差し替え → 多数 API で require_store_access が効くか全網羅</li><li><code>api/owner/users.php</code> DELETE で他 owner 除去試行（H-12）</li><li>H-01: repo 閲覧権限経由の DB credentials 入手</li></ol><h3 id="d-乗っ取られた-device-端末" tabindex="-1">d: 乗っ取られた device 端末 <a class="header-anchor" href="#d-乗っ取られた-device-端末" aria-label="Permalink to &quot;d: 乗っ取られた device 端末&quot;">​</a></h3><ol><li><code>api/kds/update-status.php</code> で任意 order を paid 化（M-01）</li><li>KDS 系 API → <code>visible_tools</code> 範囲外 endpoint 叩き</li><li>店舗内で物理的に QR 撮影 → session_token 大量収集（H-05）</li><li>POST 経路の rate limit 内での継続攻撃</li></ol><hr><h2 id="_98-8-agent-指摘で「未検証」のまま残した項目-再検証推奨" tabindex="-1">98.8 agent 指摘で「未検証」のまま残した項目（再検証推奨） <a class="header-anchor" href="#_98-8-agent-指摘で「未検証」のまま残した項目-再検証推奨" aria-label="Permalink to &quot;98.8 agent 指摘で「未検証」のまま残した項目（再検証推奨）&quot;">​</a></h2><ul><li>plan_menu_items の store_id 境界（Agent B）</li><li>course-templates 権限境界（Agent B）</li><li><code>api/store/table-merge-split.php</code> 権限（Agent B）</li><li>smaregi sync の tenant 境界（Agent B）</li><li>reservation-detail の guest 情報 enumeration（Agent B）</li><li><code>api/store/ai-generate.php</code> prompt injection filter（Agent E）</li></ul><p>これらは次フェーズで重点的に read + test。</p><h2 id="_98-9-agent-指摘を本監査で-reject-格下げしたもの-根拠つき" tabindex="-1">98.9 agent 指摘を本監査で reject / 格下げしたもの（根拠つき） <a class="header-anchor" href="#_98-9-agent-指摘を本監査で-reject-格下げしたもの-根拠つき" aria-label="Permalink to &quot;98.9 agent 指摘を本監査で reject / 格下げしたもの（根拠つき）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>agent 指摘</th><th>筆者判断</th><th>根拠</th></tr></thead><tbody><tr><td>Agent C: Stripe webhook signature validation なし（High）</td><td><strong>既防御 ✅</strong></td><td><code>api/subscription/webhook.php:37</code> で <code>verify_webhook_signature()</code> 呼び出し確認</td></tr><tr><td>Agent D: cart-event.php item_name XSS（Critical）</td><td><strong>経路なし → Low</strong></td><td><code>cart_events</code> テーブルは insert-only で consumer 側 UI 描画パスなし</td></tr><tr><td>Agent E: cron endpoint 認証なし（High）</td><td><strong>既防御 ✅</strong></td><td><code>api/cron/*.php</code> 全件 <code>php_sapi_name() !== &#39;cli&#39;</code> で HTTP 経由 403 返却</td></tr><tr><td>Agent E: localStorage に stripe_secret_key（Critical）</td><td><strong>誤検知</strong></td><td><code>posla-app.js:444-511</code> は admin 設定画面で server 保存の POST。localStorage 保存なし</td></tr><tr><td>Agent E: <code>/api/.htaccess</code> 直アクセス可（？）</td><td><strong>既防御 ✅</strong></td><td>production HTTP 403（apache FilesMatch <code>^\\.</code> ）</td></tr><tr><td>Agent E: <code>/sql/schema.sql</code> 公開（？）</td><td><strong>既防御 ✅</strong></td><td>HTTP 404（deploy 対象外）</td></tr><tr><td>Agent E: <code>/_backup_*/</code> 公開（？）</td><td><strong>既防御 ✅</strong></td><td>HTTP 403</td></tr><tr><td>Agent B: connect/callback.php auth bypass（Critical）</td><td><strong>格下げ → H-10 High</strong></td><td>Stripe 側で charges_enabled + details_submitted 検証するため DB UPDATE は「本当に onboarding 完了した時のみ」実行。CSRF risk は残るが arbitrary manipulation ではない</td></tr><tr><td>Scanner: SQL concat 4 件（Medium）</td><td><strong>reject ✅</strong></td><td>全 4 件（<code>order-history.php:48</code> <code>error-stats.php:59</code> <code>reservations.php:52</code> <code>audit-log.php:71</code>）とも <code>PDO::prepare</code> + <code>?</code> placeholder の canonical 安全パターン。<code>$where</code> / <code>$whereSql</code> / <code>$place</code> / <code>$whereClause</code> は hardcoded fragment の連結 / <code>array_fill(0, count($x), &#39;?&#39;)</code> IN 展開のみで、user input は全て <code>$params</code> 経由で bind</td></tr><tr><td>Scanner: innerHTML 439 箇所（Medium）</td><td><strong>大半 false positive</strong></td><td>ES5 codebase で <code>Utils.escapeHtml()</code> 経由の escape がテンプレート文字列内に埋まる形式（例: <code>&#39;&lt;span&gt;&#39; + Utils.escapeHtml(x) + &#39;&lt;/span&gt;&#39;</code>）が多数、grep が逐語一致できない。個別レビュー推奨だが実害は極小</td></tr></tbody></table><hr><h2 id="_98-10-検証自動化" tabindex="-1">98.10 検証自動化 <a class="header-anchor" href="#_98-10-検証自動化" aria-label="Permalink to &quot;98.10 検証自動化&quot;">​</a></h2><p><code>scripts/audit/</code> ディレクトリに実行可能なスクリプトを配置（§ scripts/audit/README.md 参照）。主要な自動回帰:</p><ul><li><code>01-auth-boundary.sh</code>: tenant 越境 POST の拒否確認</li><li><code>02-money-path.sh</code>: void / refund の重複リクエスト冪等性</li><li><code>03-customer-surface.sh</code>: QR / PIN / session rotation 確認</li><li><code>04-rate-limit.sh</code>: 各 endpoint の rate limit 発動確認</li><li><code>05-static-scan.sh</code>: 本章の C-01/C-02/C-03 + php -l + 禁則 grep（hardcoded secret / SQL concat / unescaped HTML）</li></ul><h2 id="_98-11-修正優先順位-推奨" tabindex="-1">98.11 修正優先順位（推奨） <a class="header-anchor" href="#_98-11-修正優先順位-推奨" aria-label="Permalink to &quot;98.11 修正優先順位（推奨）&quot;">​</a></h2><ol><li><strong>即時（Critical 3 件 + H-01）</strong>: <ul><li>C-01: <code>scripts/.htaccess</code> で deny</li><li>C-02: <code>public/docs-internal/.htaccess</code> に Basic auth</li><li>C-03: C-01 で包含</li><li>H-01: DB password rotation + <code>.htaccess.example</code> 化 + git filter-repo</li></ul></li><li><strong>今週中（High 残）</strong>: H-02〜H-14</li><li><strong>本番複製前最終チェック</strong>: 本章 §98.10 の 5 スクリプトを CI 化</li></ol><hr><h2 id="_98-12-更新履歴" tabindex="-1">98.12 更新履歴 <a class="header-anchor" href="#_98-12-更新履歴" aria-label="Permalink to &quot;98.12 更新履歴&quot;">​</a></h2><ul><li><strong>2026-04-21</strong>: 初版。5 分野並列 Explore agent の指摘を実コード + production HTTP で裏取り、Critical 3 / High 14 / Medium 18 / Low 10 / Reject 12 に整理。重要度の根拠を全項目に明記。本番複製前の P0 は 3 件（C-01/C-02/C-03）。</li></ul>',147)])])}const g=o(r,[["render",s]]);export{u as __pageData,g as default};
